mapper.select:
select PROGRID, PGRIDID, NUBRCEL, HOVERMD, FREZCOL, FREZROW, COLBODR, ROWBODR, STRPROW, GHEIGHT
  from ${userData.schema}.SGRIDH

   and USERKEY = #{userData.userkey}
   and USERACT = #{userData.useract}
   and PROGRID = #{param.progrid}
   and PGRIDID = #{param.pgridid}

select PROGRID, PGRIDID, DATAIDX, SORTNUM, PHIDDEN, PQALIGN, DATATYP, PQWIDTH
  from ${userData.schema}.SGRIDL

   and USERKEY = #{userData.userkey}
   and USERACT = #{userData.useract}
   and PROGRID = #{param.progrid}
   and PGRIDID = #{param.pgridid}

 order by SORTNUM asc

mapper.delete:
   delete
     from ${userData.schema}.SGRIDL
    where USERKEY = #{userData.userkey}
      and USERACT = #{userData.useract}
	  and PROGRID = #{progrid}
	  and PGRIDID = #{pgridid}

   delete
     from ${userData.schema}.SGRIDH
    where USERKEY = #{userData.userkey}
      and USERACT = #{userData.useract}
	  and PROGRID = #{progrid}
	  and PGRIDID = #{pgridid}

mapper.select:
/* selectUserList */ SELECT CONCAT(SU.USERKEY, SU.USERACT) AS rowkey , SU.USERKEY, SU.USERACT, SU.PASSWRD, SU.USERNAM, SU.ADDRESS , SU.CITYCOD, SU.RSONKEY, SU.POSTCOD, SU.NATN2KY, SU.TELPHNM , SU.EMAILAD, SU.DEPARTM, SU.EMPLOID, SU.ACAPDOC, '' AS USERTYP , SU.USERGR1, SU.USERGR2, SU.USERGR3, SU.LANGKEY, SU.DATEFMT , SU.TIMEFMT, SU.DECIFMT, SU.UTIMZON, SU.IDEXPDT, SU.PWEXPDT , SU.PWERCNT, SU.ALOCKED, SU.ALOCKMO, '' AS ROLGKEY, SU.POLPRYN , SU.POLSVYN, SU.POLSMYN, SU.POLEMYN, SU.POLDATE, SU.POLTIME , SU.APPROYN, SU.SIGUPYN, SU.APUSEYN, SU.ACTIVYN, SU.USRMEMO , SU.SOTAPYN, SU.SOTDATE, SU.SOTTIME, SU.UPDTCHK, 0 AS updtchk2 , DATE_FORMAT(SU.CREDATE,'%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(SU.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(SU.CREUSER) AS CREUSER , DATE_FORMAT(SU.LMODATE,'%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(SU.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(SU.LMOUSER) AS LMOUSER FROM ${userData.commonSchema}.SUSRMA SU
SU.APUSEYN = 'Y' AND SU.APPROYN = 'Y'
AND UPPER(SU.USERACT) LIKE CONCAT('%' , UPPER(#{param.useract}) , '%')
AND UPPER(SU.USERNAM) LIKE CONCAT('%' , UPPER(#{param.usernam}) , '%')
AND SH.USERTYP = #{param.usertyp}
AND SH.ROLGKEY = #{param.rolgkey}
AND SU.ACTIVYN = #{param.activyn}
UNION ALL SELECT CONCAT(SU.USERKEY, SU.USERACT) AS rowkey , SU.USERKEY, SU.USERACT, SU.PASSWRD, SU.USERNAM, SU.ADDRESS , SU.CITYCOD, SU.RSONKEY, SU.POSTCOD, SU.NATN2KY, SU.TELPHNM , SU.EMAILAD, SU.DEPARTM, SU.EMPLOID, SU.ACAPDOC, SH.USERTYP AS USERTYP , SU.USERGR1, SU.USERGR2, SU.USERGR3, SU.LANGKEY, SU.DATEFMT , SU.TIMEFMT, SU.DECIFMT, SU.UTIMZON, SU.IDEXPDT, SU.PWEXPDT , SU.PWERCNT, SU.ALOCKED, SU.ALOCKMO, SH.ROLGKEY AS ROLGKEY, SU.POLPRYN , SU.POLSVYN, SU.POLSMYN, SU.POLEMYN, SU.POLDATE, SU.POLTIME , SU.APPROYN, SU.SIGUPYN, 'N' as APUSEYN, SU.ACTIVYN, SU.USRMEMO , SU.SOTAPYN, SU.SOTDATE, SU.SOTTIME, SU.UPDTCHK, SH.UPDTCHK AS updtchk2 , DATE_FORMAT(SU.CREDATE,'%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(SU.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(SU.CREUSER) AS CREUSER , DATE_FORMAT(SU.LMODATE,'%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(SU.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(SU.LMOUSER) AS LMOUSER FROM ${userData.commonSchema}.SUSRMA SU INNER JOIN ${userData.commonSchema}.SUSRAP SA ON SU.USERKEY = SA.USERKEY INNER JOIN ${userData.schema}.SUSRSH SH ON SU.USERKEY = SH.USERKEY
SA.APPLKEY = ( SELECT APPLKEY FROM ${userData.commonSchema}.SAPPMA WHERE APNAMEN = #{param.apnamen} ) AND SU.APPROYN = 'Y'
AND UPPER(SU.USERACT) LIKE CONCAT('%' , UPPER(#{param.useract}) , '%')
AND UPPER(SU.USERNAM) LIKE CONCAT('%' , UPPER(#{param.usernam}) , '%')
AND SH.USERTYP = #{param.usertyp}
AND SH.ROLGKEY = #{param.rolgkey}
AND SU.ACTIVYN = #{param.activyn}
GROUP BY SU.USERKEY, SU.USERACT

mapper.insert:
    	/* insertSusrma */
		INSERT INTO PH_COMMON.SUSRMA(
			USERKEY, USERACT, PASSWRD, USERNAM, ADDRESS
