			, to_char(NOW() ,'hh24miss'), #{approyn}, #{sigupyn}, #{apuseyn}, #{activyn}
			, #{usrmemo}, #{sotapyn}, #{sotdate}, #{sottime}
			, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{useract}
			, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{useract}
		)

    	/* insertSusrmaAdmin */
